const IMAGES = [
  { src: "data:image/jpeg;base64," + img1, caption: "Republic Day Celebration" },
  { src: "data:image/jpeg;base64," + img2, caption: "Industrial Visit – Govt. Polytechnic Nuapada" },
  { src: "data:image/jpeg;base64," + img3, caption: "Independence Day – Aerial View" },
  { src: "data:image/jpeg;base64," + img4, caption: "Welcome Ceremony – GVT Polytechnic Nuapada" },
  { src: "data:image/jpeg;base64," + img5, caption: "Volleyball Tournament" },
];

export default function Gallery() {
  const [current, setCurrent] = useState(0);
  const [fade, setFade] = useState(true);
  const [progress, setProgress] = useState(0);
  const INTERVAL = 3500;

  const goTo = useCallback((index) => {
    setFade(false);
    setTimeout(() => { setCurrent(index); setFade(true); setProgress(0); }, 300);
  }, []);

  const next = useCallback(() => goTo((current + 1) % IMAGES.length), [current, goTo]);
  const prev = useCallback(() => goTo((current - 1 + IMAGES.length) % IMAGES.length), [current, goTo]);

  useEffect(() => {
    const t = setInterval(next, INTERVAL);
    return () => clearInterval(t);
  }, [next]);

  useEffect(() => {
    setProgress(0);
    const start = Date.now();
    const a = setInterval(() => setProgress(Math.min(((Date.now()-start)/INTERVAL)*100,100)), 50);
    return () => clearInterval(a);
  }, [current]);

  const btn = (side, onClick) => ({
    position:"absolute", top:"50%", [side]:"12px", transform:"translateY(-50%)",
    background:"rgba(0,0,0,0.55)", border:"none", color:"#f0b429",
    fontSize:"1.4rem", width:"42px", height:"42px", borderRadius:"50%",
    cursor:"pointer", zIndex:10,
  });

  return (
    <div style={{ background:"linear-gradient(135deg,#1a1a2e,#16213e,#0f3460)", minHeight:"60vh",
      display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center",
      fontFamily:"'Segoe UI',sans-serif", padding:"0px" }}>

      {/* <h2 style={{ color:"#f0b429", letterSpacing:"3px", marginBottom:"24px",
        textTransform:"uppercase", fontSize:"1.1rem", margin:"0 0 24px" }}>
        📸 Campus Gallery
      </h2> */}

      <div style={{ position:"relative", width:"100%", maxWidth:"1500px" }}>
        {/* Progress bar */}
        <div style={{ height:"3px", background:"#ffffff22", borderRadius:"2px", marginBottom:"10px" }}>
          <div style={{ height:"100%", width:`${progress}%`, background:"#f0b429",
            borderRadius:"2px", transition:"width 0.05s linear" }} />
        </div>

        <div style={{ borderRadius:"16px", overflow:"hidden", boxShadow:"0 20px 60px rgba(0,0,0,0.6)", position:"relative" }}>
          <img src={IMAGES[current].src} alt={IMAGES[current].caption}
            style={{ width:"100%", maxHeight:"460px", objectFit:"cover", display:"block",
              opacity: fade ? 1 : 0, transition:"opacity 0.3s ease" }} />

          <div style={{ position:"absolute", top:"14px", right:"16px",
            background:"rgba(0,0,0,0.55)", color:"#f0b429",
            padding:"4px 12px", borderRadius:"20px", fontSize:"0.85rem", fontWeight:"600" }}>
            {current+1} / {IMAGES.length}
          </div>

          <div style={{ position:"absolute", bottom:0, left:0, right:0,
            background:"linear-gradient(transparent,rgba(0,0,0,0.75))",
            color:"#fff", padding:"30px 20px 16px", fontSize:"1rem", fontWeight:"500" }}>
            {IMAGES[current].caption}
          </div>
        </div>

        <button onClick={prev} style={btn("left")}>&#8592;</button>
        <button onClick={next} style={btn("right")}>&#8594;</button>
      </div>

      <div style={{ display:"flex", gap:"10px", marginTop:"20px" }}>
        {IMAGES.map((_,i) => (
          <div key={i} onClick={() => goTo(i)} style={{
            width: i===current ? "28px" : "10px", height:"10px",
            borderRadius:"5px", background: i===current ? "#f0b429" : "#ffffff44",
            cursor:"pointer", transition:"all 0.3s ease"
          }} />
        ))}
      </div>
    </div>
  );
}
